import Vue from 'vue'
import Vuetify from 'vuetify'
import './plugins/vuetify'
import App from './App.vue'
import 'vuetify/dist/vuetify.min.css' // Ensure you are using css-loader
import Meta from 'vue-meta'
Vue.use(Meta)

/* import the fontawesome core */
import { library } from '@fortawesome/fontawesome-svg-core'

/* import font awesome icon component */
import { FontAwesomeIcon } from '@fortawesome/vue-fontawesome'

/* import specific icons */
import { faCartShopping, faUserSecret } from '@fortawesome/free-solid-svg-icons'
import { faXmark } from '@fortawesome/free-solid-svg-icons'
import { faFlag } from '@fortawesome/free-solid-svg-icons'
import { faCaretRight } from '@fortawesome/free-solid-svg-icons'
import { faFacebook, faInstagram, faTwitter, faTwitch, faYoutube } from '@fortawesome/free-brands-svg-icons'
import { faIdCard } from '@fortawesome/free-solid-svg-icons'

/* add icons to the library */
library.add(faUserSecret, faXmark, faFlag, faCaretRight, faTwitter, faTwitch, faYoutube, faFacebook, faInstagram, faCartShopping, faIdCard)

/* add font awesome icon component */
Vue.component('font-awesome-icon', FontAwesomeIcon)


Vue.config.productionTip = false
Vue.use(Vuetify)

new Vue({
  render: h => h(App),
}).$mount('#app')
